import React from "react";

function Preview({ data, template }) {
  if (template === "template2") {
    return (
      <div id="resume-preview" style={{ width: "50%", padding: "20px", background: "#f4f4f4" }}>
        <h2>{data.name}</h2>
        <p>{data.email}</p>

        <h3>Skills</h3>
        <p>{data.skills}</p>

        <h3>Projects</h3>
        {data.projects.map((item, i) => (
          <div key={i}>
            <p><strong>{item.title}</strong></p>
            <p>{item.tech}</p>
            <p>{item.description}</p>
          </div>
        ))}
      </div>
    );
  }

  return (
    <div
      id="resume-preview"
      style={{
        width: "50%",
        padding: "30px",
        background: "#fff",
        border: "1px solid #ddd",
        fontFamily: "Arial",
        lineHeight: "1.6"
      }}
    >
      <h1>{data.name}</h1>
      <p>{data.email} | {data.phone}</p>

      <hr />

      <h3>Skills</h3>
      <p>{data.skills}</p>

      <hr />

      <h3>Education</h3>
      {data.education.map((item, i) => (
        <div key={i}>
          <p><strong>{item.degree}</strong></p>
          <p>{item.college}</p>
          <p>{item.year}</p>
        </div>
      ))}

      {data.experience[0].company && (
        <>
          <hr />
          <h3>Experience</h3>
          {data.experience.map((item, i) => (
            <div key={i}>
              <p><strong>{item.role}</strong></p>
              <p>{item.company}</p>
              <p>{item.year}</p>
            </div>
          ))}
        </>
      )}

      <hr />

      <h3>Projects</h3>
      {data.projects.map((item, i) => (
        <div key={i}>
          <p><strong>{item.title}</strong></p>
          <p>{item.tech}</p>
          <p>{item.description}</p>
        </div>
      ))}
    </div>
  );
}

export default Preview;
